targets.expr:
(
  ( 100 * kubelet_volume_stats_used_bytes{persistentvolumeclaim=~"$pvc",namespace=~"$namespace"}
      / kubelet_volume_stats_capacity_bytes)
  * on(namespace, persistentvolumeclaim) group_right()
    max by(namespace, persistentvolumeclaim, pod, node) (
      kube_pod_spec_volumes_persistentvolumeclaims_info
        * on(namespace, pod) group_left(node) kube_pod_info{pod=~"$pod",node=~"$node"}
    )
)
* on(namespace, persistentvolumeclaim) group_left(storageclass)
  kube_persistentvolumeclaim_info

kubelet_volume_stats_used_bytes{persistentvolumeclaim=~"$pvc",namespace=~"$namespace"}
  * on(namespace, persistentvolumeclaim) group_right()
    max by(namespace, persistentvolumeclaim, pod, node) (
      kube_pod_spec_volumes_persistentvolumeclaims_info
        * on(namespace, pod) group_left(node) kube_pod_info{pod=~"$pod",node=~"$node"}
    )
    * on(namespace, persistentvolumeclaim) group_left(storageclass)
  kube_persistentvolumeclaim_info

kubelet_volume_stats_capacity_bytes{persistentvolumeclaim=~"$pvc",namespace=~"$namespace"}
* on(namespace, persistentvolumeclaim) group_right()
    max by(namespace, persistentvolumeclaim, pod, node) (
      kube_pod_spec_volumes_persistentvolumeclaims_info
        * on(namespace, pod) group_left(node) kube_pod_info{pod=~"$pod",node=~"$node"}
    )
    * on(namespace, persistentvolumeclaim) group_left(storageclass)
  kube_persistentvolumeclaim_info

kube_persistentvolumeclaim_resource_requests_storage_bytes{persistentvolumeclaim=~"$pvc",namespace=~"$namespace"}
* on(namespace, persistentvolumeclaim) group_right()
    max by(namespace, persistentvolumeclaim, pod, node) (
      kube_pod_spec_volumes_persistentvolumeclaims_info
        * on(namespace, pod) group_left(node) kube_pod_info{pod=~"$pod",node=~"$node"}
    )
    * on(namespace, persistentvolumeclaim) group_left(storageclass)
  kube_persistentvolumeclaim_info

# ---- hostpath PVCs: openebs used / kubelet capacity ----
(
  100 *
  (
    openebs_hostpath_volume_used_bytes
    * on(persistentvolume) group_left(namespace, persistentvolumeclaim)
      label_replace(kube_persistentvolumeclaim_info, "persistentvolume", "$1", "volumename", "(.+)")
  )
  / on(namespace, persistentvolumeclaim) group_left()
    kubelet_volume_stats_capacity_bytes
)
* on(namespace, persistentvolumeclaim) group_right()
  max by(namespace, persistentvolumeclaim, pod, node) (
    kube_pod_spec_volumes_persistentvolumeclaims_info
      * on(namespace, pod) group_left(node) kube_pod_info{pod=~"$pod", node=~"$node"}
  )
* on(namespace, persistentvolumeclaim) group_left(storageclass)
  kube_persistentvolumeclaim_info{storageclass="openebs-hostpath", persistentvolumeclaim=~"$pvc", namespace=~"$namespace"}

